const langSelect=document.querySelector(".header__nav-lang"),current=langSelect.querySelector(".header__nav-current"),dropdown=langSelect.querySelector(".header__nav-dropdown"),options=langSelect.querySelectorAll(".header__nav-option");current.addEventListener("click",(()=>{dropdown.style.display="block"===dropdown.style.display?"none":"block"})),options.forEach((e=>{e.addEventListener("click",(()=>{const n=e.querySelector("img").src,o=e.querySelector("span").textContent;current.innerHTML=`\n      <img src="${n}" alt="${o}">\n      <span>${o}</span>\n      <svg class="icon icon-angle-down"><use xlink:href="#icon-angle-down"></use></svg>\n    `,dropdown.style.display="none"}))})),document.addEventListener("click",(e=>{langSelect.contains(e.target)||(dropdown.style.display="none")})),console.log("Hello");